import{_ as s,o as n,c as e,ak as t}from"./chunks/framework.DwHlt8HN.js";const h=JSON.parse('{"title":"分布式协调服务","description":"","frontmatter":{},"headers":[],"relativePath":"distributed/zookeeper/index.md","filePath":"distributed/zookeeper/index.md","lastUpdated":1774319300000}'),r={name:"distributed/zookeeper/index.md"};function p(l,a,i,d,o,c){return n(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="分布式协调服务" tabindex="-1">分布式协调服务 <a class="header-anchor" href="#分布式协调服务" aria-label="Permalink to “分布式协调服务”">​</a></h1><p>在分布式系统中，有一个经典的问题：</p><p>多个节点如何协同？谁来当 leader？节点之间如何感知彼此的存在？</p><p><strong>分布式协调服务，就是来解决这些问题的。</strong></p><p>ZooKeeper、etcd、Nacos，是三个最主流的解决方案。</p><h2 id="模块速览" tabindex="-1">模块速览 <a class="header-anchor" href="#模块速览" aria-label="Permalink to “模块速览”">​</a></h2><p>分布式协调服务分为三个部分：ZooKeeper、etcd、Nacos。</p><table tabindex="0"><thead><tr><th>章节</th><th>篇数</th><th>核心内容</th></tr></thead><tbody><tr><td><a href="/distributed/zookeeper/data-model">ZooKeeper</a></td><td>8 篇</td><td>数据模型、Watch、Session、Leader 选举、ACL、应用场景</td></tr><tr><td><a href="/distributed/etcd/architecture">etcd</a></td><td>3 篇</td><td>架构原理、Raft + MVCC、Kubernetes 应用</td></tr><tr><td><a href="/distributed/nacos/architecture">Nacos</a></td><td>5 篇</td><td>注册中心、配置中心、集群部署、临时/持久实例</td></tr></tbody></table><h2 id="三者对比" tabindex="-1">三者对比 <a class="header-anchor" href="#三者对比" aria-label="Permalink to “三者对比”">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>ZooKeeper</th><th>etcd</th><th>Nacos</th></tr></thead><tbody><tr><td>一致性协议</td><td>ZAB</td><td>Raft</td><td>Raft</td></tr><tr><td>数据模型</td><td>ZNode 树</td><td>Key-Value</td><td>Key-Value</td></tr><tr><td>Watch 机制</td><td>一次性触发</td><td>持续监听</td><td>持续监听</td></tr><tr><td>生态</td><td>大数据（Hadoop、Kafka）</td><td>Kubernetes</td><td>Spring Cloud</td></tr><tr><td>适用场景</td><td>配置管理、分布式锁</td><td>服务发现、配置中心</td><td>注册中心、配置中心</td></tr></tbody></table><h2 id="zookeeper-的核心能力" tabindex="-1">ZooKeeper 的核心能力 <a class="header-anchor" href="#zookeeper-的核心能力" aria-label="Permalink to “ZooKeeper 的核心能力”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ZooKeeper 的三大核心能力：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 数据模型：树形结构的 ZNode</span></span>
<span class="line"><span>   ├── 持久节点：永久存在</span></span>
<span class="line"><span>   ├── 临时节点：会话结束后自动删除</span></span>
<span class="line"><span>   ├── 顺序节点：自动编号</span></span>
<span class="line"><span>   └── 版本号：乐观锁支持</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. Watch 机制：事件驱动</span></span>
<span class="line"><span>   ├── 一次性触发</span></span>
<span class="line"><span>   └── 事件类型：创建、删除、修改、孩子变化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 选举机制：FastLeaderElection</span></span>
<span class="line"><span>   ├── 要素：Epoch、zxid、ServerID</span></span>
<span class="line"><span>   └── 选出的 Leader 拥有最新数据</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h2 id="nacos-的双模式" tabindex="-1">Nacos 的双模式 <a class="header-anchor" href="#nacos-的双模式" aria-label="Permalink to “Nacos 的双模式”">​</a></h2><p>Nacos 同时支持<strong>注册中心</strong>和<strong>配置中心</strong>两种模式：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>注册中心：</span></span>
<span class="line"><span>├─ 服务注册 / 注销</span></span>
<span class="line"><span>├─ 服务发现</span></span>
<span class="line"><span>├─ 健康检查：心跳机制</span></span>
<span class="line"><span>└─ 临时实例 vs 持久实例</span></span>
<span class="line"><span></span></span>
<span class="line"><span>配置中心：</span></span>
<span class="line"><span>├─ 配置管理：热更新</span></span>
<span class="line"><span>├─ 命名空间隔离</span></span>
<span class="line"><span>├─ 配置监听：变更推送</span></span>
<span class="line"><span>└─ 多配置共享</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><h2 id="面试高频问题" tabindex="-1">面试高频问题 <a class="header-anchor" href="#面试高频问题" aria-label="Permalink to “面试高频问题”">​</a></h2><h3 id="q1-zookeeper-和-etcd-的区别" tabindex="-1">Q1：ZooKeeper 和 etcd 的区别？ <a class="header-anchor" href="#q1-zookeeper-和-etcd-的区别" aria-label="Permalink to “Q1：ZooKeeper 和 etcd 的区别？”">​</a></h3><blockquote><p>「从设计目标看，ZooKeeper 是通用的分布式协调服务，etcd 专注于服务发现和配置管理。 从协议看，两者都用一致性协议，但 etcd 是纯 Raft，ZooKeeper 是 ZAB。 从生态看，etcd 是 Kubernetes 的存储后端，ZooKeeper 是大数据生态的核心组件。」</p></blockquote><h3 id="q2-nacos-和-eureka-的区别" tabindex="-1">Q2：Nacos 和 Eureka 的区别？ <a class="header-anchor" href="#q2-nacos-和-eureka-的区别" aria-label="Permalink to “Q2：Nacos 和 Eureka 的区别？”">​</a></h3><blockquote><p>「Eureka 已经停止维护，Nacos 是更全面的替代方案。 Nacos 支持注册中心和配置中心，Eureka 只支持注册中心。 Nacos 支持一致性协议（AP + CP），Eureka 只支持 AP。 Nacos 有更活跃的社区和更完善的功能。」</p></blockquote><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to “延伸阅读”">​</a></h2><p>分布式协调服务的选择建议：</p><ul><li><strong>Spring Cloud + 微服务</strong>：选 Nacos（生态最完善）</li><li><strong>Kubernetes 生态</strong>：选 etcd（K8s 深度集成）</li><li><strong>大数据生态</strong>：选 ZooKeeper（久经生产验证）</li><li><strong>通用场景</strong>：都可以，关键看团队熟悉度</li></ul>`,23)])])}const u=s(r,[["render",p]]);export{h as __pageData,u as default};
